import{_ as a,o as e,c as i,ag as l}from"./chunks/framework.CvgP6Fyv.js";const o="/bima/web-page-light.svg",r="/bima/web-page-dark.svg",s="/bima/shopping-light.svg",n="/bima/shopping-dark.svg",d="/bima/mail-light.svg",c="/bima/mail-dark.svg",h="/bima/wechat-light.svg",p="/bima/wechat-dark.svg",f=JSON.parse('{"title":"关于我们","description":"","frontmatter":{},"headers":[{"level":1,"title":"关于我们","slug":"关于我们","link":"#关于我们","children":[{"level":2,"title":"数据一览","slug":"数据一览","link":"#数据一览","children":[]},{"level":2,"title":"我们的理念","slug":"我们的理念","link":"#我们的理念","children":[]},{"level":2,"title":"技术能力","slug":"技术能力","link":"#技术能力","children":[]},{"level":2,"title":"业务服务","slug":"业务服务","link":"#业务服务","children":[{"level":3,"title":"CAS 单点登录系统","slug":"cas-单点登录系统","link":"#cas-单点登录系统","children":[]},{"level":3,"title":"智能中间件集成验证脚手架","slug":"智能中间件集成验证脚手架","link":"#智能中间件集成验证脚手架","children":[]},{"level":3,"title":"Keycloak 扩展开发","slug":"keycloak-扩展开发","link":"#keycloak-扩展开发","children":[]},{"level":3,"title":"技术咨询服务","slug":"技术咨询服务","link":"#技术咨询服务","children":[]}]},{"level":2,"title":"联系我们","slug":"联系我们","link":"#联系我们","children":[]}]}],"relativePath":"bima/关于我们.md","filePath":"bima/关于我们.md"}'),g={name:"bima/关于我们.md"};function b(k,t,m,u,v,S){return e(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="关于我们" tabindex="-1">关于我们 <a class="header-anchor" href="#关于我们" aria-label="Permalink to &quot;关于我们&quot;">​</a></h1><p>北京必码科技工作室（简称&quot;必码&quot;），是一家专注于开源项目定制开发与技术服务的工作室。我们秉承&quot;只写必要的代码&quot;的核心理念，围绕企业级身份认证与微服务架构两大核心方向，提供轻量化、可落地的技术解决方案。</p><h2 id="数据一览" tabindex="-1">数据一览 <a class="header-anchor" href="#数据一览" aria-label="Permalink to &quot;数据一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数据</th></tr></thead><tbody><tr><td>CAS 覆盖版本</td><td>5.3.x / 6.6.x / 7.3.x 三大版本线</td></tr><tr><td>脚手架架构形态</td><td>Spring Boot / Dubbo / Spring Cloud 三种</td></tr><tr><td>Keycloak 扩展类型</td><td>SPI User Storage / Event Listener / SM Crypto 三种</td></tr><tr><td>覆盖 Java 版本</td><td>8 / 11 / 17 / 21</td></tr><tr><td>集成中间件</td><td>8 大主流中间件（MyBatis、Elasticsearch、Kafka、MongoDB、RabbitMQ、Redis、RocketMQ、LDAP）</td></tr><tr><td>构建工具支持</td><td>Gradle + Maven 双构建体系</td></tr></tbody></table><h2 id="我们的理念" tabindex="-1">我们的理念 <a class="header-anchor" href="#我们的理念" aria-label="Permalink to &quot;我们的理念&quot;">​</a></h2><p>必码坚持&quot;小而精、专而深&quot;的服务原则，聚焦开源生态，专注技术落地。我们深知企业在使用开源产品时面临的&quot;适配难、定制难&quot;痛点，凭借丰富的开源二次开发经验，从需求分析到交付运维，全程细致跟进，力求以最小的成本解决最实际的问题。</p><h2 id="技术能力" tabindex="-1">技术能力 <a class="header-anchor" href="#技术能力" aria-label="Permalink to &quot;技术能力&quot;">​</a></h2><p>我们深耕 Java 后端技术生态，主要涵盖以下领域：</p><ul><li><strong>身份认证与授权</strong>：基于 Apereo CAS 的企业级单点登录系统定制开发，覆盖 OAuth 2.0 + OIDC 双协议集成、自定义认证处理器与自定义返回值、JWT AccessToken 加密签名、多因素认证等场景</li><li><strong>微服务架构</strong>：Spring Boot 单体、Dubbo 分布式 RPC、Spring Cloud 微服务三种架构形态的设计、选型与落地实施，同一业务场景提供可直接对比的参考实现</li><li><strong>中间件集成</strong>：MyBatis、Elasticsearch、Kafka、MongoDB、RabbitMQ、Redis、RocketMQ、LDAP 等主流中间件的深度集成与调优，一站式完成接入调试、功能测试与可用性验证</li><li><strong>AI 能力集成</strong>：Spring AI + Ollama 本地大模型、OpenAI API 双模式对接、SSE 流式实时聊天与文章创作、Chroma 文本向量嵌入、内置写作风格系统等多元化 AI 应用落地</li><li><strong>容器化与部署</strong>：Docker 多阶段构建、Jenkins CI/CD 流水线、Kubernetes 容器编排，内置标准化 DockerFile 与部署脚本，一键完成容器打包与自动化部署</li><li><strong>Keycloak 扩展开发</strong>：基于 Keycloak SPI 的扩展开发，包括用户存储扩展、事件监听器扩展和国密算法扩展，支持多种数据库类型、消息队列系统和中国国家标准密码算法</li></ul><h2 id="业务服务" tabindex="-1">业务服务 <a class="header-anchor" href="#业务服务" aria-label="Permalink to &quot;业务服务&quot;">​</a></h2><h3 id="cas-单点登录系统" tabindex="-1">CAS 单点登录系统 <a class="header-anchor" href="#cas-单点登录系统" aria-label="Permalink to &quot;CAS 单点登录系统&quot;">​</a></h3><p>基于 Apereo 基金会维护的 CAS（Central Authentication Service）项目，提供面向企业的轻量化定制开发服务，解决多系统统一身份认证问题。覆盖 5.3.x（JDK 8）、6.6.x（JDK 11）、7.3.x（JDK 21 / Spring Boot 3.x）三个大版本线，支持 Gradle 和 Maven 双构建体系，提供完整的开发基座、配置模板和部署方案。</p><p><strong>核心能力：</strong> WAR 转 JAR 现代化架构升级 · JDBC + LDAP 双源认证 · 自定义认证处理器与自定义返回值 · OAuth 2.0 + OIDC 双协议认证 · JWT AccessToken 加密签名 · Redis 分布式票据注册表 · 安全加固（强制关闭默认账号） · 自定义启动类支持本地 Debug · 前端资源全量提取与品牌定制 · 国际化多语言 · 监控与日志体系 · Docker / Jenkins CI/CD 自动化部署</p><p><a href="/dev/cas-overlay/">查看 CAS 版本文档</a> · <a href="/tech/cas-overlay/">阅读 CAS 深度解析系列</a></p><h3 id="智能中间件集成验证脚手架" tabindex="-1">智能中间件集成验证脚手架 <a class="header-anchor" href="#智能中间件集成验证脚手架" aria-label="Permalink to &quot;智能中间件集成验证脚手架&quot;">​</a></h3><p>面向开发者打造的一站式微服务项目脚手架，深度融合 AI 能力与主流中间件集成方案。同一业务场景在 Spring Boot 单体、Dubbo RPC、Spring Cloud 微服务三种架构下的完整实现，为架构选型提供可直接对比的参考。基于 Spring Boot 3.5.12 + Java 17，内置 LayUI 可视化 Web 操作界面，零代码门槛即可完成各类中间件功能调试与 AI 能力在线演示。</p><p><strong>核心能力：</strong> 8 大中间件集成验证（MyBatis / Elasticsearch / Kafka / MongoDB / RabbitMQ / Redis / RocketMQ / LDAP） · AI 全场景集成（Ollama + OpenAI 双模式、SSE 流式聊天与文章创作、Chroma 文本向量嵌入、内置写作风格系统） · OAuth 2.0 + OIDC 双协议统一认证 · 多数据源动态配置 · 全覆盖内置测试用例 · 多环境无缝适配 · Docker / Jenkins CI/CD · Maven 多模块工程化</p><p><a href="/dev/smart-scaffold/">查看脚手架文档</a> · <a href="/tech/smart-scaffold/">阅读 Smart-Scaffold 深度解析系列</a></p><h3 id="keycloak-扩展开发" tabindex="-1">Keycloak 扩展开发 <a class="header-anchor" href="#keycloak-扩展开发" aria-label="Permalink to &quot;Keycloak 扩展开发&quot;">​</a></h3><p>基于 Keycloak 开源项目，提供面向企业的扩展开发服务，解决 Keycloak 原生功能不足的问题。支持三种核心扩展类型：用户存储扩展、事件监听器扩展和国密算法扩展，满足企业在身份认证、事件处理和加密需求等方面的定制化需求。</p><p><strong>核心能力：</strong> 多数据库类型支持（MySQL、SQL Server、Oracle、达梦、金仓、OceanBase、GaussDB） · 多消息队列集成（Kafka、RabbitMQ、RocketMQ） · 国密算法集成（SM2、SM3、SM4） · 灵活的扩展架构 · 完整的开发示例 · 标准化部署方案</p><p><a href="/dev/keycloak-extension/">查看 Keycloak 扩展开发文档</a></p><h3 id="技术咨询服务" tabindex="-1">技术咨询服务 <a class="header-anchor" href="#技术咨询服务" aria-label="Permalink to &quot;技术咨询服务&quot;">​</a></h3><p>提供专业的开源技术咨询服务，帮助企业制定合理的技术路线，解决技术难题，提升系统架构的可靠性和可扩展性。</p><table tabindex="0"><thead><tr><th>服务方向</th><th>说明</th></tr></thead><tbody><tr><td>架构设计</td><td>微服务架构选型（Spring Boot / Dubbo / Spring Cloud）、系统架构评审与优化</td></tr><tr><td>技术指导</td><td>CAS 单点登录方案设计、中间件集成方案制定、开源项目最佳实践</td></tr><tr><td>安全评估</td><td>认证授权安全审计、依赖漏洞扫描、安全配置加固</td></tr><tr><td>性能调优</td><td>JVM 调优、数据库连接池优化、缓存策略设计、慢查询治理</td></tr><tr><td>工程化咨询</td><td>CI/CD 流水线设计、多模块项目结构规划、容器化部署方案</td></tr></tbody></table><h2 id="联系我们" tabindex="-1">联系我们 <a class="header-anchor" href="#联系我们" aria-label="Permalink to &quot;联系我们&quot;">​</a></h2><p>如有合作意向或技术咨询需求，欢迎通过以下方式联系我们。</p><div class="contact-info"><div class="contact-item"><img src="'+o+'" class="vp-light-only" width="24" height="24"><img src="'+r+'" class="vp-dark-only" width="24" height="24"><span>官方网址：https://bima.cc</span></div></div><div class="contact-info"><div class="contact-item"><img src="'+s+'" class="vp-light-only" width="24" height="24"><img src="'+n+'" class="vp-dark-only" width="24" height="24"><span>官方店铺：https://bima.taobao.com</span></div></div><div class="contact-info"><div class="contact-item"><img src="'+d+'" class="vp-light-only" width="24" height="24"><img src="'+c+'" class="vp-dark-only" width="24" height="24"><span>联系邮箱：bima.cc@qq.com</span></div></div><div class="contact-info"><div class="contact-item"><img src="'+h+'" class="vp-light-only" width="24" height="24"><img src="'+p+'" class="vp-dark-only" width="24" height="24"><span>联系微信：e18929958</span></div></div>',31)])])}const A=a(g,[["render",b]]);export{f as __pageData,A as default};
